We don't seem to have proper unit tests for this, `prevector_tests` passes with:
```C++
constexpr bool operator==(const prevector& other) const { return true; }
```

Can you please add a unit test commit before the change that exercises the current behavior, and a second commit that changes the implementation without changing the tests? Maybe something simple like:
```patch
diff --git a/src/test/prevector_tests.cpp b/src/test/prevector_tests.cpp
--- a/src/test/prevector_tests.cpp	(revision 2678abe902c69ab5af5450d6fdf40ead834b1e26)
+++ b/src/test/prevector_tests.cpp	(date 1772635055198)
@@ -313,4 +313,21 @@
     }
 }

+BOOST_AUTO_TEST_CASE(PrevectorEqualityRegression)
+{
+    using pretype = prevector<8, int>;
+
+    const pretype empty{};
+    const pretype one_a{1, 42};
+    const pretype one_b{1, 42};
+    const pretype one_c{1, 43};
+    const pretype two{2, 42}; // Same prefix as one_a, but longer.
+
+    BOOST_CHECK((empty == empty) && !(empty != empty));
+    BOOST_CHECK((one_a == one_b) && !(one_a != one_b));
+    BOOST_CHECK(!(empty == one_a) && (empty != one_a));
+    BOOST_CHECK(!(one_a == one_c) && (one_a != one_c));
+    BOOST_CHECK(!(one_a == two) && (one_a != two));
+}
+
 BOOST_AUTO_TEST_SUITE_END()
```

