 #include <vector>

 struct nontrivial_t
@@ -111,6 +116,71 @@
     });
 }

+static void PrevectorEqualScriptMix(benchmark::Bench& bench)
+{
+    static constexpr size_t BASE_SCRIPTS{2048};
+    static constexpr size_t DUPLICATES{256};
+    static constexpr size_t PREFIX_VARIANTS{256};
+    static constexpr size_t RANDOM_COMPARISONS{4096};
+
+    FastRandomContext rng{/*fDeterministic=*/true};
+    std::vector<CScriptBase> scripts;
+    scripts.reserve(BASE_SCRIPTS + DUPLICATES + PREFIX_VARIANTS);
+
+    for (size_t i = 0; i < BASE_SCRIPTS; ++i) {
+        const size_t size = 4 + rng.randrange(257);
+        CScriptBase script(size, 0);
+        for (auto& byte : script) byte = rng.randbits(8);
+        // Stamp with a unique id so base scripts are distinct.
+        script[size - 4] = static_cast<uint8_t>(i);
+        script[size - 3] = static_cast<uint8_t>(i >> 8);
+        script[size - 2] = static_cast<uint8_t>(i >> 16);
+        script[size - 1] = static_cast<uint8_t>(i >> 24);
+        scripts.emplace_back(std::move(script));
+    }
+
+    std::vector<std::pair<size_t, size_t>> comparisons;
+    comparisons.reserve(DUPLICATES + PREFIX_VARIANTS + RANDOM_COMPARISONS);
+
+    for (size_t i = 0; i < DUPLICATES; ++i) {
+        const size_t src_idx = (i * 13) % BASE_SCRIPTS;
+        const size_t dup_idx = scripts.size();
+        scripts.push_back(scripts[src_idx]);
+        comparisons.emplace_back(src_idx, dup_idx);
+    }
+
+    for (size_t i = 0; i < PREFIX_VARIANTS; ++i) {
+        const size_t src_idx = (i * 29) % BASE_SCRIPTS;
+        const CScriptBase& src = scripts[src_idx];
+        const size_t trim = std::min<size_t>(src.size() - 1, 1 + (i % 8));
+        const size_t prefix_size = src.size() - trim;
+        const size_t prefix_idx = scripts.size();
+        scripts.emplace_back(src.begin(), src.begin() + prefix_size);
+        comparisons.emplace_back(src_idx, prefix_idx);
+    }
+
+    for (size_t i = 0; i < RANDOM_COMPARISONS; ++i) {
+        const size_t lhs = rng.randrange(BASE_SCRIPTS);
+        size_t rhs = rng.randrange(BASE_SCRIPTS);
+        if (rhs == lhs) rhs = (rhs + 1) % BASE_SCRIPTS;
+        comparisons.emplace_back(lhs, rhs);
+    }
+
+    const auto count_equal_pairs = [&] {
+        size_t true_count{0};
+        for (const auto& [lhs_idx, rhs_idx] : comparisons) {
+            true_count += scripts[lhs_idx] == scripts[rhs_idx];
+        }
+        return true_count;
+    };
+    const size_t expected_true{DUPLICATES};
+
+    bench.batch(comparisons.size()).run([&] {
+        const size_t true_count{count_equal_pairs()};
+        Assert(true_count == expected_true);
+    });
+}
+
 #define PREVECTOR_TEST(name)                                         \
     static void Prevector##name##Nontrivial(benchmark::Bench& bench) \
     {                                                                \
@@ -129,3 +199,4 @@
 PREVECTOR_TEST(Deserialize)
 PREVECTOR_TEST(FillVectorDirect)
 PREVECTOR_TEST(FillVectorIndirect)
+BENCHMARK(PrevectorEqualScriptMix);
